mapper.select:
SELECT s.id AS submission_id, s.submission_code, s.team_id, w.work_name, t.team_name, w.competition_id, w.track_id, s.submission_time, s.status AS submission_status FROM submission s LEFT JOIN work w ON s.work_id = w.id LEFT JOIN team t ON s.team_id = t.id WHERE s.status = 'SUBMITTED'
AND w.competition_id = #{competitionId}
AND NOT EXISTS ( SELECT 1 FROM judge_review jr WHERE jr.submission_id = s.id ) ORDER BY s.submission_time DESC
